"use strict";(self.webpackChunkwoocommerce_ebay_connector=self.webpackChunkwoocommerce_ebay_connector||[]).push([[188],{7387(e,a,t){t.r(a),t.d(a,{comp:()=>n,data:()=>r});var i=t(641);const o={},n=(0,t(6262).A)(o,[["render",function(e,a){return(0,i.uX)(),(0,i.CE)("div",null,[...a[0]||(a[0]=[(0,i.Fv)('<h1 id="features-–-woocommerce-ebay-connector" tabindex="-1"><a class="header-anchor" href="#features-–-woocommerce-ebay-connector"><span>Features – WooCommerce eBay Connector</span></a></h1><p>The WooCommerce eBay Connector plugin integrates your WooCommerce store with eBay, providing two-way synchronization for products, orders, and inventory.</p><hr><h2 id="core-features" tabindex="-1"><a class="header-anchor" href="#core-features"><span>Core Features</span></a></h2><ul><li>Import simple and variable eBay products in the WooCommerce store.</li><li>Import custom-created shop categories from eBay to the WooCommerce store.</li><li>The connector has Automatic Inventory Management functionality.</li><li>Import eBay orders in the WooCommerce store.</li><li>Export simple and variable products from the WooCommerce store to eBay.</li><li>Map custom-created shop categories on eBay with the WooCommerce store category.</li><li>Admin will update imported product details.</li><li>Admin will configure the return policy details for exported products.</li><li>The product&#39;s SKU, name, description, stock, images, and categories export and import along with the product.</li><li>Supports product synchronization with eBay conditions and specifications.</li><li>Admin will configure multiple eBay accounts.</li><li>Sandbox mode is available for testing and development.</li><li>Configure default product payment and shipping details.</li><li>Admin will set the events in the Realtime setting for the auto-update of the product.</li><li>Admin will select the process for the auto-update.</li><li>Admin will also configure the International Shipping Service.</li><li>Admin will manage the Real-Time Sync and update product information as per the selected event.</li><li>The count of the products added at the backend can be checked.</li><li>Separate logs for real-time sync events.</li></ul><hr><h2 id="supported-ebay-marketplaces" tabindex="-1"><a class="header-anchor" href="#supported-ebay-marketplaces"><span>Supported eBay Marketplaces</span></a></h2><p>The plugin supports a wide range of global eBay marketplaces:</p><ul><li>eBay Motors</li><li>eBay United States</li><li>eBay Canada (English and French)</li><li>eBay UK</li><li>eBay Australia</li><li>eBay Austria</li><li>eBay Belgium (French and Dutch)</li><li>eBay France</li><li>eBay Germany</li><li>eBay Italy</li><li>eBay Netherlands</li><li>eBay Spain</li><li>eBay Switzerland</li><li>eBay Hong Kong</li><li>eBay India</li><li>eBay Ireland</li><li>eBay Malaysia</li><li>eBay Philippines</li><li>eBay Poland</li><li>eBay Singapore</li></ul><hr><h2 id="real-time-synchronization-features" tabindex="-1"><a class="header-anchor" href="#real-time-synchronization-features"><span>Real-Time Synchronization Features</span></a></h2><p>The connector supports the following Real-Time Synchronization features:</p><h3 id="automatic-creation" tabindex="-1"><a class="header-anchor" href="#automatic-creation"><span>Automatic Creation</span></a></h3><p>When a product is created in the eBay store, its updates will reflect in the WooCommerce store. The synced details include the category, description, title, SKU, price, stock, images, and attributes.</p><h3 id="automatic-update" tabindex="-1"><a class="header-anchor" href="#automatic-update"><span>Automatic Update</span></a></h3><p>When a product is edited in the eBay store, the update reflects in the WooCommerce store. The synced details include the category, description, title, SKU, price, stock, images, and attributes.</p><h3 id="automatic-deletion" tabindex="-1"><a class="header-anchor" href="#automatic-deletion"><span>Automatic Deletion</span></a></h3><p>When an item is deleted from the eBay store, the change reflects in the WooCommerce store.</p><hr><h2 id="automatic-inventory-management" tabindex="-1"><a class="header-anchor" href="#automatic-inventory-management"><span>Automatic Inventory Management</span></a></h2><p>The WooCommerce eBay Connector features Automatic Inventory Management, streamlining inventory control and reducing manual work.</p><ul><li>When a product is sold or updated on eBay, WooCommerce automatically adjusts its stock.</li><li>If a product goes out of stock on eBay, it is also marked out of stock in WooCommerce.</li><li>This automatic inventory sync works both ways, based on the Real-Time Sync settings, ensuring WooCommerce changes also reflect on eBay.</li></ul><hr><h2 id="compatibility" tabindex="-1"><a class="header-anchor" href="#compatibility"><span>Compatibility</span></a></h2><ul><li>Compatible with WooCommerce <strong>Cart and Checkout blocks</strong></li><li>Compatible with <strong>High-Performance Order Storage (HPOS)</strong></li><li>Supports multiple stores simultaneously</li></ul><blockquote><p><strong>Note:</strong> The Connector supports pictures in the following file formats: JPEG, BMP, GIF, TIF, PNG.</p></blockquote>',26)])])}]]),r=JSON.parse('{"path":"/documentation/features.html","title":"Features – WooCommerce eBay Connector","lang":"en-US","frontmatter":{},"git":{"updatedTime":1771481506000,"contributors":[{"name":"shakir.hussain","username":"","email":"shakir.hussain421@webkul.in","commits":1}],"changelog":[{"hash":"277c5a1bdc13e06551e102ee26c728b6b048e50b","time":1771481506000,"email":"shakir.hussain421@webkul.in","author":"shakir.hussain","message":"updated ebay blog and move to dev"}]},"filePathRelative":"documentation/features.md"}')}}]);